```cpp
// add+modify_eas_records.hpp
#pragma once

#include <filesystem>
#include <map>
#include <rfl.hpp>
#include <rfl/json.hpp>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <string>
#include <vector>

#include "eas_common.hpp"
using namespace sqlgen;
using namespace sqlgen::literals;

template<typename T>
void add_eas_records(const std::string& table_name,
                     const std::vector<T>& records) {
  // Map table names to their corresponding types
  static const std::map<std::string, rfl::Type> table_type_map = {
    {"Student", rfl::type<Student>()},
    {"Course", rfl::type<Course>()},
    {"Score", rfl::type<Score>()},
    {"Major", rfl::type<Major>()}
  };

  // Get the connection
  auto conn_result = sqlgen::sqlite::connect(db_path);
  if (!conn_result) {
    throw std::runtime_error("Failed to connect to database");
  }
  auto conn = conn_result.value();

  // Get the appropriate type for the table
  auto it = table_type_map.find(table_name);
  if (it == table_type_map.end()) {
    throw std::runtime_error("Unknown table: " + table_name);
  }

  // Use sqlgen::write to insert records
  auto write_result = sqlgen::write(conn, records);
  if (!write_result) {
    throw std::runtime_error("Failed to write records to table: " + table_name);
  }
}

void modify_eas_records_by_id(const std::string& table_name,
                               const std::string& record_id,
                               const std::string& col_name,
                               const std::string& new_value) {
  // Map table names to their corresponding types and primary key columns
  static const std::map<std::string, std::pair<rfl::Type, std::string>> table_info = {
    {"Student", {rfl::type<Student>(), "SNo"}},
    {"Course", {rfl::type<Course>(), "CID"}},
    {"Score", {rfl::type<Score>(), "ScID"}},
    {"Major", {rfl::type<Major>(), "MID"}}
  };

  // Get the connection
  auto conn_result = sqlgen::sqlite::connect(db_path);
  if (!conn_result) {
    throw std::runtime_error("Failed to connect to database");
  }
  auto conn = conn_result.value();

  // Get table information
  auto it = table_info.find(table_name);
  if (it == table_info.end()) {
    throw std::runtime_error("Unknown table: " + table_name);
  }

  auto [record_type, pk_col] = it->second;

  // Build the update query using sqlgen's fluent interface
  auto update_query = sqlgen::update(record_type) 
                    | sqlgen::set(col_name, new_value)
                    | sqlgen::where(pk_col == record_id);

  // Execute the update
  auto result = update_query(conn);
  if (!result) {
    throw std::runtime_error("Failed to update record in table: " + table_name);
  }
}

void delete_eas_records_by_id(const std::string& table_name,
                               const std::string& record_id) {
  // Map table names to their corresponding types and primary key columns
  static const std::map<std::string, std::pair<rfl::Type, std::string>> table_info = {
    {"Student", {rfl::type<Student>(), "SNo"}},
    {"Course", {rfl::type<Course>(), "CID"}},
    {"Score", {rfl::type<Score>(), "ScID"}},
    {"Major", {rfl::type<Major>(), "MID"}}
  };

  // Get the connection
  auto conn_result = sqlgen::sqlite::connect(db_path);
  if (!conn_result) {
    throw std::runtime_error("Failed to connect to database");
  }
  auto conn = conn_result.value();

  // Get table information
  auto it = table_info.find(table_name);
  if (it == table_info.end()) {
    throw std::runtime_error("Unknown table: " + table_name);
  }

  auto [record_type, pk_col] = it->second;

  // Build the delete query using sqlgen's fluent interface
  auto delete_query = sqlgen::delete_from(record_type) 
                    | sqlgen::where(pk_col == record_id);

  // Execute the delete
  auto result = delete_query(conn);
  if (!result) {
    throw std::runtime_error("Failed to delete record from table: " + table_name);
  }
}
```

## Key Implementation Details:

1. **Type Mapping**: Uses `rfl::type<T>()` to map table names to their corresponding C++ struct types for compile-time type safety.

2. **Database Connection**: Uses `sqlgen::sqlite::connect(db_path)` to establish connection to the SQLite database.

3. **Insert Operation**: Leverages `sqlgen::write()` function which handles both single objects and containers, automatically generating the appropriate SQL INSERT statements.

4. **Update Operation**: Uses `sqlgen::update()` with `sqlgen::set()` and `sqlgen::where()` to construct type-safe UPDATE queries with proper column validation.

5. **Delete Operation**: Uses `sqlgen::delete_from()` with `sqlgen::where()` to construct type-safe DELETE queries.

6. **Error Handling**: Properly handles `Result` types returned by sqlgen operations and throws descriptive exceptions on failures.

7. **Primary Key Handling**: Correctly identifies and uses the primary key columns for each table based on the struct definitions.

The implementation follows sqlgen's fluent interface pattern and leverages the library's type-safe query building capabilities while maintaining proper error handling and resource management.

