```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace delete_inactive_users {

struct User {
  sqlgen::PrimaryKey<int> user_id;
  std::string username;
  std::optional<sqlgen::DateTime> last_login;
  std::string status = "active";
};

int delete_inactive_users() {
  using namespace sqlgen::literals;

  // 1. Connect to the database
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    return -1; // Connection failed
  }

  // 2. Start a transaction
  auto transaction_result = sqlgen::begin_transaction(conn_result);
  if (!transaction_result) {
    return -1; // Transaction start failed
  }

  // 3. Construct DELETE statement with WHERE condition
  auto delete_stmt = sqlgen::delete_from<User> 
                   | sqlgen::where("last_login"_c < "2025-01-01");

  // 4. Execute the DELETE statement within the transaction
  auto delete_result = delete_stmt(transaction_result);
  if (!delete_result) {
    return -1; // DELETE execution failed
  }

  // 5. Commit the transaction
  auto commit_result = sqlgen::commit(delete_result);
  if (!commit_result) {
    return -1; // Commit failed
  }

  // 6. Return the result of the commit operation
  return commit_result ? 0 : -1;
}

} // namespace delete_inactive_users
```

