namespace soft_delete_records {

struct Document {
  sqlgen::PrimaryKey<int> doc_id;
  std::string title;
  int is_deleted = 0;
  std::optional<sqlgen::DateTime> deleted_at;
};

bool soft_delete_records(const std::vector<int>& ids) {
    // Connect to the SQLite database
    auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
    if (!conn_result) {
        return false;
    }
    auto conn = *conn_result;

    // Begin transaction for safety
    auto begin_result = conn->begin_transaction();
    if (!begin_result) {
        return false;
    }

    try {
        // Create update statement using sqlgen::update
        auto update_stmt = sqlgen::update<Document>(
            "is_deleted"_c.set(1),
            "deleted_at"_c.set(sqlgen::current_timestamp())
        );

        // Add WHERE clause with IN condition for the list of doc_ids
        auto where_condition = "doc_id"_c.in(ids);
        auto full_stmt = update_stmt | sqlgen::where(where_condition);

        // Execute the update
        auto result = full_stmt(conn);

        if (!result) {
            // Rollback on failure
            conn->rollback();
            return false;
        }

        // Commit transaction on success
        auto commit_result = conn->commit();
        return commit_result;

    } catch (...) {
        // Rollback on exception
        conn->rollback();
        return false;
    }
}

}  // namespace soft_delete_records
