#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace update_set_operations {

struct Account {
  sqlgen::PrimaryKey<int> account_id;
  double balance;
  std::string status;
};

/**
 * description: update_set_operations.
 * This function demonstrates how to use set operations in update statements using sqlgen write API.
 * It returns true if the update operations are successful, and false otherwise.
 * Returns: bool.
 */
bool update_set_operations() {
  using namespace sqlgen::literals;

  // 1. Connect to the database
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    return false;
  }

  // 2. Create the Account table using write with empty container
  std::vector<Account> empty_accounts;
  auto create_table_result = sqlgen::write(conn_result.value(), empty_accounts);
  if (!create_table_result) {
    return false;
  }

  // 3. Update balances and statuses using set operations
  auto update_result = create_table_result.value()
    .and_then([](const auto& conn) {
      // Update account with account_id = 1
      return sqlgen::update<Account>(
        "balance"_c.set(100.0),
        "status"_c.set("active")
      ) | sqlgen::where("account_id"_c == 1)(conn);
    })
    .and_then([](const auto& conn) {
      // Update account with account_id = 2
      return sqlgen::update<Account>(
        "balance"_c.set(200.0),
        "status"_c.set("inactive")
      ) | sqlgen::where("account_id"_c == 2)(conn);
    });

  if (!update_result) {
    return false;
  }

  // 4. Verify changes by reading the updated data
  auto verify_result = update_result.value()
    .and_then([](const auto& conn) {
      // Verify account_id = 1
      return (sqlgen::read<std::vector<Account>> | sqlgen::where("account_id"_c == 1))(conn);
    })
    .and_then([](const auto& accounts) {
      if (accounts.empty() || accounts[0].account_id != 1 || accounts[0].balance != 100.0 || accounts[0].status != "active") {
        return rfl::error("Verification failed for account_id = 1");
      }
      return rfl::ok(accounts);
    })
    .and_then([](const auto& conn) {
      // Verify account_id = 2
      return (sqlgen::read<std::vector<Account>> | sqlgen::where("account_id"_c == 2))(conn);
    })
    .and_then([](const auto& accounts) {
      if (accounts.empty() || accounts[0].account_id != 2 || accounts[0].balance != 200.0 || accounts[0].status != "inactive") {
        return rfl::error("Verification failed for account_id = 2");
      }
      return rfl::ok(true);
    });

  return verify_result.has_value();
}

}  // namespace update_set_operations
```

